export declare function makeTextNode(value: string, start: number, end: number, source: string): TextNode;
export declare function makeLiquidDocParamNode(paramName: TextNode, paramType: TextNode | null, paramDescription: TextNode | null, required: boolean, start: number, end: number, source: string): LiquidDocParamNode;
